{
  "name": "Gemini Audio Transcriber",
  "description": "A powerful speech-to-text application powered by Gemini 2.5 Flash. Record your voice and get instant, accurate transcriptions.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TranscriptionState {
  status: 'idle' | 'recording' | 'processing' | 'success' | 'error';
  text: string | null;
  error: string | null;
}

export interface AudioVisualizerProps {
  isRecording: boolean;
}

import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:audio/webm;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  try {
    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);

    // Default to a common audio mime type if the blob doesn't have one,
    // though MediaRecorder usually provides one.
    const mimeType = audioBlob.type || 'audio/webm';

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: "Transcribe the speech in this audio file. Output only the transcription, without any introductory text, timestamps, or descriptions."
          }
        ]
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    return text;
  } catch (error: any) {
    console.error("Transcription error:", error);
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { TranscriptionState } from '../types';

interface AudioRecorderProps {
  onTranscriptionStart: () => void;
  onTranscriptionComplete: (text: string) => void;
  onTranscriptionError: (error: string) => void;
  currentState: TranscriptionState['status'];
}

export const AudioRecorder: React.FC<AudioRecorderProps> = ({
  onTranscriptionStart,
  onTranscriptionComplete,
  onTranscriptionError,
  currentState
}) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);

  // To stop recording if component unmounts
  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        // Stop all tracks to release microphone
        stream.getTracks().forEach(track => track.stop());

        // Pass blob to parent for processing
        processAudio(blob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);

      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      onTranscriptionError("Could not access microphone. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const processAudio = async (blob: Blob) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const text = await transcribeAudio(blob);
      onTranscriptionComplete(text);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing';

  return (
    <div className="flex flex-col items-center justify-center space-y-8 w-full max-w-md mx-auto p-6">

      {/* Visualizer Area */}
      <div className={`relative flex items-center justify-center w-48 h-48 rounded-full border-4 transition-all duration-300 ${isRecording ? 'border-red-500 bg-red-50' : 'border-slate-200 bg-white'}`}>
        {isRecording ? (
          <div className="flex items-center space-x-1 h-16">
            <div className="w-2 bg-red-500 h-8 rounded-full animate-wave" style={{ animationDelay: '0ms' }}></div>
            <div className="w-2 bg-red-500 h-12 rounded-full animate-wave" style={{ animationDelay: '100ms' }}></div>
            <div className="w-2 bg-red-500 h-6 rounded-full animate-wave" style={{ animationDelay: '200ms' }}></div>
            <div className="w-2 bg-red-500 h-10 rounded-full animate-wave" style={{ animationDelay: '300ms' }}></div>
            <div className="w-2 bg-red-500 h-4 rounded-full animate-wave" style={{ animationDelay: '400ms' }}></div>
          </div>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
          </svg>
        )}

        {/* Timer Overlay */}
        {isRecording && (
          <div className="absolute -bottom-8 text-red-600 font-mono font-medium text-lg">
            {formatDuration(duration)}
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="flex flex-col items-center space-y-4 w-full">
        {!isRecording && !isProcessing && (
          <button
            onClick={startRecording}
            className="group relative flex items-center justify-center px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-lg hover:shadow-xl transition-all duration-200 w-full sm:w-auto"
          >
            <span className="flex items-center space-x-3 text-lg font-semibold">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 18.5a6.5 6.5 0 100-13 6.5 6.5 0 000 13z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5.5a3.5 3.5 0 100 7 3.5 3.5 0 000-7z" />
              </svg>
              <span>Start Recording</span>
            </span>
          </button>
        )}

        {isRecording && (
          <button
            onClick={stopRecording}
            className="flex items-center justify-center px-8 py-4 bg-white border-2 border-red-500 text-red-600 hover:bg-red-50 rounded-full shadow-md transition-all duration-200 w-full sm:w-auto"
          >
            <span className="flex items-center space-x-3 text-lg font-semibold">
              <div className="w-4 h-4 bg-red-600 rounded-sm"></div>
              <span>Stop Recording</span>
            </span>
          </button>
        )}

        {isProcessing && (
          <div className="flex items-center justify-center space-x-3 text-indigo-600 py-4">
            <svg className="animate-spin h-6 w-6" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            <span className="text-lg font-medium">Processing Audio...</span>
          </div>
        )}

        <p className="text-sm text-slate-500 text-center max-w-xs">
          {isRecording ? "Listening... Tap stop when finished." : isProcessing ? "Gemini is analyzing your speech." : "Tap to start capturing your thoughts."}
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TranscriptionState } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
  });

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string) => {
    setState({ status: 'success', text, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null });
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
              Gemini Transcribe
            </h1>
          </div>
          <div className="text-xs font-medium px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-full border border-indigo-100">
            Powered by Gemini 2.5 Flash
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        <div className="space-y-12">

          {/* Recorder Section */}
          <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
             <div className="p-1">
               <AudioRecorder
                currentState={state.status}
                onTranscriptionStart={handleStart}
                onTranscriptionComplete={handleComplete}
                onTranscriptionError={handleError}
              />
             </div>
          </section>

          {/* Error Message */}
          {state.status === 'error' && (
            <div className="bg-red-50 border border-red-200 rounded-2xl p-6 flex items-start space-x-4 animate-fade-in">
              <div className="flex-shrink-0">
                <svg className="h-6 w-6 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div className="flex-1">
                <h3 className="text-sm font-medium text-red-800">Transcription Failed</h3>
                <p className="mt-1 text-sm text-red-700">{state.error}</p>
                <button 
                  onClick={reset}
                  className="mt-3 text-sm font-medium text-red-600 hover:text-red-500"
                >
                  Try Again &rarr;
                </button>
              </div>
            </div>
          )}

          {/* Results Section */}
          {state.status === 'success' && state.text && (
            <section className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-semibold text-slate-800">Transcription Result</h2>
                <div className="flex space-x-2">
                  <button 
                    onClick={() => navigator.clipboard.writeText(state.text || "")}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="Copy to clipboard"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                    </svg>
                  </button>
                  <button 
                    onClick={reset}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="New recording"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                  </button>
                </div>
              </div>

              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
                <div className="prose prose-slate max-w-none">
                  <p className="whitespace-pre-wrap text-lg leading-relaxed text-slate-700">
                    {state.text}
                  </p>
                </div>
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Simple Footer */}
      <footer className="py-8 text-center text-slate-400 text-sm">
        <p>&copy; {new Date().getFullYear()} Gemini Audio Transcriber</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:audio/webm;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const transcribeAudio = async (audioBlob: Blob, language: string = 'Auto-detect'): Promise<string> => {
  try {
    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);

    // Default to a common audio mime type if the blob doesn't have one,
    // though MediaRecorder usually provides one.
    const mimeType = audioBlob.type || 'audio/webm';

    let prompt = "Transcribe the speech in this audio file. Output only the transcription, without any introductory text, timestamps, or descriptions.";

    if (language && language !== 'Auto-detect') {
      prompt = `Transcribe the speech in this audio file. The language is ${language}. Output only the transcription in ${language}, without any introductory text, timestamps, or descriptions.`;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    return text;
  } catch (error: any) {
    console.error("Transcription error:", error);
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { TranscriptionState } from '../types';

interface AudioRecorderProps {
  onTranscriptionStart: () => void;
  onTranscriptionComplete: (text: string) => void;
  onTranscriptionError: (error: string) => void;
  currentState: TranscriptionState['status'];
}

const LANGUAGES = [
  'Auto-detect',
  'English',
  'Spanish',
  'French',
  'German',
  'Hindi',
  'Chinese (Mandarin)',
  'Japanese',
  'Korean',
  'Portuguese',
  'Italian',
  'Russian',
  'Arabic',
  'Indonesian',
  'Vietnamese',
  'Turkish'
];

export const AudioRecorder: React.FC<AudioRecorderProps> = ({
  onTranscriptionStart,
  onTranscriptionComplete,
  onTranscriptionError,
  currentState
}) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [selectedLanguage, setSelectedLanguage] = useState('Auto-detect');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);

  // To stop recording if component unmounts
  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        // Stop all tracks to release microphone
        stream.getTracks().forEach(track => track.stop());

        // Pass blob to parent for processing
        processAudio(blob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);

      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      onTranscriptionError("Could not access microphone. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const processAudio = async (blob: Blob) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const text = await transcribeAudio(blob, selectedLanguage);
      onTranscriptionComplete(text);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing';

  return (
    <div className="flex flex-col items-center justify-center space-y-8 w-full max-w-md mx-auto p-6">

      {/* Language Selector - Only show when idle to avoid changing mid-recording */}
      {!isRecording && !isProcessing && (
        <div className="w-full max-w-xs animate-fade-in">
          <label htmlFor="language-select" className="block text-sm font-medium text-slate-500 mb-2 text-center">
            Transcription Language
          </label>
          <div className="relative">
            <select
              id="language-select"
              value={selectedLanguage}
              onChange={(e) => setSelectedLanguage(e.target.value)}
              className="block w-full pl-4 pr-10 py-2.5 text-base border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-xl bg-slate-50 text-slate-700 shadow-sm transition-all hover:bg-white"
            >
              {LANGUAGES.map((lang) => (
                <option key={lang} value={lang}>
                  {lang}
                </option>
              ))}
            </select>
            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
              <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
              </svg>
            </div>
          </div>
        </div>
      )}

      {/* Visualizer Area */}
      <div className={`relative flex items-center justify-center w-48 h-48 rounded-full border-4 transition-all duration-300 ${isRecording ? 'border-red-500 bg-red-50' : 'border-slate-200 bg-white'}`}>
        {isRecording ? (
          <div className="flex items-center space-x-1 h-16">
            <div className="w-2 bg-red-500 h-8 rounded-full animate-wave" style={{ animationDelay: '0ms' }}></div>
            <div className="w-2 bg-red-500 h-12 rounded-full animate-wave" style={{ animationDelay: '100ms' }}></div>
            <div className="w-2 bg-red-500 h-6 rounded-full animate-wave" style={{ animationDelay: '200ms' }}></div>
            <div className="w-2 bg-red-500 h-10 rounded-full animate-wave" style={{ animationDelay: '300ms' }}></div>
            <div className="w-2 bg-red-500 h-4 rounded-full animate-wave" style={{ animationDelay: '400ms' }}></div>
          </div>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
          </svg>
        )}

        {/* Timer Overlay */}
        {isRecording && (
          <div className="absolute -bottom-8 text-red-600 font-mono font-medium text-lg">
            {formatDuration(duration)}
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="flex flex-col items-center space-y-4 w-full">
        {!isRecording && !isProcessing && (
          <button
            onClick={startRecording}
            className="group relative flex items-center justify-center px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-lg hover:shadow-xl transition-all duration-200 w-full sm:w-auto"
          >
