                    </svg>
                    <span>Start Recording</span>
                  </span>
                </button>
              )}

              {isRecording && (
                <button
                  onClick={stopRecording}
                  className="flex items-center justify-center px-8 py-4 bg-white border-2 border-red-500 text-red-600 hover:bg-red-50 rounded-full shadow-md transition-all duration-200 w-full sm:w-auto"
