              </svg>
            </div>
            <span className="text-xl font-medium text-indigo-900">
              {mode === 'record' ? 'Transcribing Recording...' : 'Processing File...'}
            </span>
            <p className="text-slate-500 mt-2">Generating structured notes.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TranscriptionState } from './types';

// Declare marked from global scope (loaded via script tag)
declare const marked: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
  });

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string) => {
    setState({ status: 'success', text, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null });
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    // Use marked if available, otherwise fallback to basic formatting
    if (typeof marked !== 'undefined') {
      return { __html: marked.parse(text) };
    }
    return { __html: text };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
