export const transcribeAudio = async (audioBlob: Blob, language: string = 'Auto-detect', template?: string): Promise<string> => {
  try {
    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);

    // Default to a common audio mime type if the blob doesn't have one
    const mimeType = audioBlob.type || 'audio/webm';

    let systemInstruction = "You are an expert transcriber and meeting secretary. Your task is to analyze audio and produce clear, structured notes.";

    let prompt = "Analyze the speech in this audio file. Create a comprehensive set of structured neat notes that capture all key points, details, and arguments. Use clear headings, bullet points, and paragraphs. Output valid Markdown.";

    if (template && template.trim().length > 0) {
       prompt = `Analyze the speech in this audio file and extract information to fill out the following template.

       STRICTLY FOLLOW THIS STRUCTURE AND FORMAT:
       ${template}

       Instructions:
       1. Fill in the bracketed placeholders [ ] with information from the audio.
       2. If specific information (like Date or Members) is not explicitly mentioned, try to infer it from context or mark it as "Not mentioned".
       3. Maintain the headings and structure exactly as provided in the template.
       4. Output valid Markdown.
       `;
    }

    if (language && language !== 'Auto-detect') {
      prompt += `\n\nIMPORTANT: The language of the output must be ${language}.`;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        systemInstruction: systemInstruction
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    return text;
  } catch (error: any) {
    console.error("Transcription error:", error);
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

