export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  mode,
  onModeChange
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleModeChange = (newMode: 'general' | 'meeting' | 'custom') => {
    onModeChange(newMode);
    if (newMode === 'meeting') {
      onTemplateChange(MEETING_TEMPLATE);
    } else if (newMode === 'general') {
      onTemplateChange('');
    }
    // If custom, keep current or clear if it was meeting? 
    // Let's keep it empty if switching to custom from general, but keep content if switching from meeting to edit it.
    if (newMode === 'custom' && mode === 'general') {
        onTemplateChange(MEETING_TEMPLATE); // Start with meeting template as base for custom
