import React, { useState, useRef, useEffect } from 'react';
import { TranscriptionState } from '../types';

interface AudioRecorderProps {
  onTranscriptionStart: () => void;
  onTranscriptionComplete: (text: string) => void;
  onTranscriptionError: (error: string) => void;
  currentState: TranscriptionState['status'];
  template: string;
}

const LANGUAGES = [
  'Auto-detect',
  'Tunisian Dialect',
  'Saudi Dialect',
  'English',
  'Spanish',
  'French',
  'German',
  'Hindi',
  'Chinese (Mandarin)',
  'Japanese',
  'Korean',
  'Portuguese',
  'Italian',
  'Russian',
  'Arabic',
  'Indonesian',
  'Vietnamese',
  'Turkish'
];

export const AudioRecorder: React.FC<AudioRecorderProps> = ({
  onTranscriptionStart,
  onTranscriptionComplete,
  onTranscriptionError,
  currentState,
  template
}) => {
  const [mode, setMode] = useState<'record' | 'upload'>('record');
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [selectedLanguage, setSelectedLanguage] = useState('Auto-detect');
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // To stop recording if component unmounts
  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        // Stop all tracks to release microphone
        stream.getTracks().forEach(track => track.stop());

        // Pass blob to parent for processing
        processAudio(blob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);

      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      onTranscriptionError("Could not access microphone. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 500 * 1024 * 1024) { // 500MB limit
        onTranscriptionError("File size too large. Please upload files under 500MB.");
        return;
      }
      processAudio(file);
    }
  };

  const processAudio = async (blob: Blob) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const text = await transcribeAudio(blob, selectedLanguage, template);
      onTranscriptionComplete(text);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing';

  return (
    <div className="flex flex-col items-center justify-center space-y-8 w-full max-w-md mx-auto p-6">

      {/* Mode Toggle & Language - Only show when idle */}
      {!isRecording && !isProcessing && (
        <div className="w-full space-y-6 animate-fade-in">

          {/* Mode Switcher */}
          <div className="flex p-1 bg-slate-100 rounded-xl">
            <button
              onClick={() => setMode('record')}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${
                mode === 'record' 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Record Audio
            </button>
            <button
              onClick={() => setMode('upload')}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${
                mode === 'upload' 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Upload File
            </button>
          </div>

          {/* Language Selector */}
          <div>
            <label htmlFor="language-select" className="block text-xs font-semibold text-slate-500 mb-2 uppercase tracking-wider text-center">
              Target Language / Dialect
            </label>
            <div className="relative">
              <select
                id="language-select"
                value={selectedLanguage}
                onChange={(e) => setSelectedLanguage(e.target.value)}
                className="block w-full pl-4 pr-10 py-2.5 text-base border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-xl bg-slate-50 text-slate-700 shadow-sm transition-all hover:bg-white cursor-pointer"
              >
                {LANGUAGES.map((lang) => (
                  <option key={lang} value={lang}>
                    {lang}
                  </option>
                ))}
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-slate-500">
                <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
                </svg>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Action Area */}
      <div className="w-full flex justify-center min-h-[200px] items-center">
        {mode === 'record' ? (
          /* Recorder Interface */
          <div className="flex flex-col items-center space-y-8 w-full">
            <div className={`relative flex items-center justify-center w-48 h-48 rounded-full border-4 transition-all duration-300 ${isRecording ? 'border-red-500 bg-red-50' : 'border-slate-200 bg-white'}`}>
              {isRecording ? (
                <div className="flex items-center space-x-1 h-16">
                  <div className="w-2 bg-red-500 h-8 rounded-full animate-wave" style={{ animationDelay: '0ms' }}></div>
                  <div className="w-2 bg-red-500 h-12 rounded-full animate-wave" style={{ animationDelay: '100ms' }}></div>
                  <div className="w-2 bg-red-500 h-6 rounded-full animate-wave" style={{ animationDelay: '200ms' }}></div>
                  <div className="w-2 bg-red-500 h-10 rounded-full animate-wave" style={{ animationDelay: '300ms' }}></div>
                  <div className="w-2 bg-red-500 h-4 rounded-full animate-wave" style={{ animationDelay: '400ms' }}></div>
                </div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                </svg>
              )}

              {isRecording && (
                <div className="absolute -bottom-8 text-red-600 font-mono font-medium text-lg">
                  {formatDuration(duration)}
                </div>
              )}
            </div>

            <div className="flex flex-col items-center space-y-4 w-full">
              {!isRecording && !isProcessing && (
                <button
                  onClick={startRecording}
                  className="group relative flex items-center justify-center px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-lg hover:shadow-xl transition-all duration-200 w-full sm:w-auto"
                >
                  <span className="flex items-center space-x-3 text-lg font-semibold">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 18.5a6.5 6.5 0 100-13 6.5 6.5 0 000 13z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5.5a3.5 3.5 0 100 7 3.5 3.5 0 000-7z" />
                    </svg>
                    <span>Start Recording</span>
                  </span>
                </button>
              )}

              {isRecording && (
                <button
                  onClick={stopRecording}
                  className="flex items-center justify-center px-8 py-4 bg-white border-2 border-red-500 text-red-600 hover:bg-red-50 rounded-full shadow-md transition-all duration-200 w-full sm:w-auto"
                >
                  <span className="flex items-center space-x-3 text-lg font-semibold">
                    <div className="w-4 h-4 bg-red-600 rounded-sm"></div>
                    <span>Stop Recording</span>
                  </span>
                </button>
              )}
            </div>
          </div>
        ) : (
          /* Upload Interface */
          <div className="w-full flex flex-col items-center animate-fade-in">
             {!isProcessing ? (
                <div 
                  className="w-full h-48 border-2 border-dashed border-indigo-200 rounded-3xl bg-indigo-50/50 flex flex-col items-center justify-center cursor-pointer hover:bg-indigo-50 transition-colors"
                  onClick={() => fileInputRef.current?.click()}
                >
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="audio/*" 
                    onChange={handleFileUpload}
                  />
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                  </div>
                  <p className="text-indigo-900 font-medium">Click to upload audio file</p>
                  <p className="text-indigo-400 text-sm mt-1">MP3, WAV, M4A (Max 500MB)</p>
                </div>
             ) : null}
          </div>
        )}

        {isProcessing && (
