// Declare marked from global scope (loaded via script tag)
declare const marked: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
  });
  const [template, setTemplate] = useState<string>('');
  const [templateMode, setTemplateMode] = useState<'general' | 'meeting' | 'custom'>('general');

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string) => {
    setState({ status: 'success', text, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null });
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const handleExportWord = () => {
    if (!state.text) return;

    // Convert Markdown to HTML for the Word export
    let htmlContent = '';
    if (typeof marked !== 'undefined') {
       htmlContent = marked.parse(state.text);
    } else {
       htmlContent = `<pre>${state.text}</pre>`;
    }

    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' " +
         "xmlns:w='urn:schemas-microsoft-com:office:word' " +
         "xmlns='http://www.w3.org/TR/REC-html40'>" +
         "<head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title>" +
         "<style>body { font-family: 'Calibri', sans-serif; font-size: 11pt; }</style>" +
         "</head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + htmlContent + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    // Use marked if available, otherwise fallback to basic formatting
    if (typeof marked !== 'undefined') {
      return { __html: marked.parse(text) };
    }
    return { __html: text };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
