import { GoogleGenAI } from "@google/genai";

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not set");
  }
  return new GoogleGenAI({ apiKey });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the data URL prefix (e.g., "data:audio/webm;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const transcribeAudio = async (
  audioBlob: Blob, 
  language: string = 'Auto-detect', 
  template?: string,
  isJsonMode: boolean = false
): Promise<{ text: string, json?: any }> => {
  try {
    const ai = getGeminiClient();
    const base64Data = await blobToBase64(audioBlob);
    const mimeType = audioBlob.type || 'audio/webm';

    let systemInstruction = "You are an expert transcriber and meeting secretary. Your task is to analyze audio and produce clear, structured output.";

    let prompt = "";

    if (isJsonMode) {
      prompt = `Analyze the speech in this audio file and extract information to fill out the requested fields.

      INSTRUCTIONS:
      ${template}

      IMPORTANT:
      - Return ONLY valid JSON.
      - Do not include markdown formatting like \`\`\`json.
      - Ensure all keys requested in the instructions are present in the JSON object.
      `;
    } else {
      prompt = "Analyze the speech in this audio file. Create a comprehensive set of structured neat notes that capture all key points, details, and arguments. Use clear headings, bullet points, and paragraphs. Output valid Markdown.";

      if (template && template.trim().length > 0) {
         prompt = `Analyze the speech in this audio file and extract information to fill out the following template.

         STRICTLY FOLLOW THIS STRUCTURE AND FORMAT:
         ${template}

         Instructions:
         1. Fill in the bracketed placeholders [ ] with information from the audio.
         2. Maintain the headings and structure exactly as provided in the template.
         3. Output valid Markdown.
         `;
      }
    }

    if (language && language !== 'Auto-detect') {
      prompt += `\n\nIMPORTANT: The language of the content must be ${language}.`;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: prompt }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: isJsonMode ? 'application/json' : 'text/plain'
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No transcription generated.");
    }

    if (isJsonMode) {
      try {
        const json = JSON.parse(text);
        return { text: JSON.stringify(json, null, 2), json };
      } catch (e) {
        console.error("Failed to parse JSON response:", e);
        // Fallback to text if JSON parsing fails, though responseMimeType should prevent this
        return { text };
      }
    }

    return { text };
  } catch (error: any) {
    console.error("Transcription error:", error);
    throw new Error(error.message || "Failed to transcribe audio.");
  }
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TemplateSelector } from './components/TemplateSelector';
import { TranscriptionState } from './types';

// Declare globals for libraries loaded via script tags
declare const marked: any;
declare const PizZip: any;
declare const docxtemplater: any;
declare const saveAs: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
    jsonResult: null
  });
  const [template, setTemplate] = useState<string>('');
  const [templateMode, setTemplateMode] = useState<'general' | 'meeting' | 'custom' | 'word_template'>('general');
  const [wordTemplateFile, setWordTemplateFile] = useState<ArrayBuffer | null>(null);
  const [wordTemplateName, setWordTemplateName] = useState<string | null>(null);

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string, json?: any) => {
    setState({ status: 'success', text, jsonResult: json, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error, jsonResult: null });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null, jsonResult: null });
  };

  const handleWordTemplateUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        setWordTemplateFile(e.target.result as ArrayBuffer);
        setWordTemplateName(file.name);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const handleExportWord = () => {
    // If we have a JSON result and a Word template, use docxtemplater
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
         });

         // Render the document with the JSON data from Gemini
         doc.render(state.jsonResult);

         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });

         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          console.error("Docxtemplater error:", error);
          alert("Error generating Word document. Please ensure your template matches the extracted keys.");
       }
       return;
    }

    // Fallback: Export standard Markdown/HTML to Word
    if (!state.text) return;

    let htmlContent = '';
    if (typeof marked !== 'undefined') {
       htmlContent = marked.parse(state.text);
    } else {
       htmlContent = `<pre>${state.text}</pre>`;
    }

    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' " +
         "xmlns:w='urn:schemas-microsoft-com:office:word' " +
         "xmlns='http://www.w3.org/TR/REC-html40'>" +
         "<head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title>" +
         "<style>body { font-family: 'Calibri', sans-serif; font-size: 11pt; }</style>" +
         "</head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + htmlContent + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    if (typeof marked !== 'undefined') {
      return { __html: marked.parse(text) };
    }
    return { __html: text };
  };

  const isWordTemplateMode = templateMode === 'word_template';

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-indigo-100 selection:text-indigo-800">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
              Gemini Transcribe
            </h1>
          </div>
          <div className="text-xs font-medium px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-full border border-indigo-100">
            Powered by Gemini 2.5 Flash
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        <div className="space-y-12">

          {/* Settings Section */}
          <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden no-print">
             <div className="p-6 pb-0">
               <TemplateSelector 
                  template={template} 
                  onTemplateChange={setTemplate}
                  mode={templateMode}
                  onModeChange={setTemplateMode}
                  wordTemplateName={wordTemplateName}
                  onWordTemplateUpload={handleWordTemplateUpload}
               />
             </div>
             <div className="p-1 border-t border-slate-100">
               <AudioRecorder
                currentState={state.status}
                onTranscriptionStart={handleStart}
                onTranscriptionComplete={handleComplete}
                onTranscriptionError={handleError}
                template={template}
                isJsonMode={isWordTemplateMode}
              />
             </div>
          </section>

          {/* Error Message */}
          {state.status === 'error' && (
            <div className="bg-red-50 border border-red-200 rounded-2xl p-6 flex items-start space-x-4 animate-fade-in no-print">
              <div className="flex-shrink-0">
                <svg className="h-6 w-6 text-red-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div className="flex-1">
                <h3 className="text-sm font-medium text-red-800">Transcription Failed</h3>
                <p className="mt-1 text-sm text-red-700">{state.error}</p>
                <button 
                  onClick={reset}
                  className="mt-3 text-sm font-medium text-red-600 hover:text-red-500"
                >
                  Try Again &rarr;
                </button>
              </div>
            </div>
          )}

          {/* Results Section */}
          {state.status === 'success' && (
            <section className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between no-print flex-wrap gap-2">
                <h2 className="text-lg font-semibold text-slate-800">
                  {state.jsonResult ? 'Extracted Data' : 'Transcribed Notes'}
                </h2>
                <div className="flex space-x-2">
                   <button 
                    onClick={handleExportWord}
                    className="flex items-center space-x-2 px-3 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium"
                    title={isWordTemplateMode ? "Fill Word Template" : "Export as Word Doc"}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                       <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                    <span>{isWordTemplateMode ? 'Download Filled Word Doc' : 'Export Word'}</span>
                  </button>

                  {!isWordTemplateMode && (
                    <button 
                      onClick={handlePrintPDF}
                      className="flex items-center space-x-2 px-3 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg transition-colors shadow-sm text-sm font-medium"
                      title="Export as PDF"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                      </svg>
                      <span>Export PDF</span>
                    </button>
                  )}

                  <button 
                    onClick={() => navigator.clipboard.writeText(state.text || "")}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="Copy to clipboard"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                    </svg>
                  </button>
                  <button 
                    onClick={reset}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="New recording"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                  </button>
                </div>
              </div>

              <div id="results-container" className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 md:p-10">
                <h1 className="text-3xl font-bold mb-6 hidden print-only">Transcribed Notes</h1>

                {/* Render JSON as text if in JSON mode, otherwise Render Markdown */}
                {state.jsonResult ? (
                  <div className="bg-slate-50 p-4 rounded-lg font-mono text-sm overflow-x-auto border border-slate-200">
                    <h3 className="text-slate-500 font-semibold mb-2 uppercase text-xs">Data extracted for template:</h3>
                    <pre className="text-indigo-700">{JSON.stringify(state.jsonResult, null, 2)}</pre>
                    <p className="mt-4 text-xs text-slate-500 italic">
                      * This data will be inserted into the <strong>{wordTemplateName || 'template'}</strong> file when you click "Download Filled Word Doc".
                    </p>
                  </div>
                ) : (
                  <div 
                    className="prose prose-slate max-w-none prose-headings:font-semibold prose-a:text-indigo-600"
                    dangerouslySetInnerHTML={getMarkdownHtml(state.text)}
                  />
                )}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Simple Footer */}
      <footer className="py-8 text-center text-slate-400 text-sm no-print">
        <p>&copy; {new Date().getFullYear()} Gemini Audio Transcriber</p>
      </footer>
    </div>
  );
};

