// Helper to analyze audio quality
const analyzeAudioQuality = async (blob: Blob): Promise<string | null> => {
  if (blob.size === 0) return "Audio file is empty.";

  // Skip deep analysis for large files (>10MB) to prevent browser freeze
  if (blob.size > 10 * 1024 * 1024) return null;

  try {
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    const arrayBuffer = await blob.arrayBuffer();
    const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);

    // Check Duration
    if (audioBuffer.duration < 0.5) {
      audioContext.close();
      return "Recording is too short (less than 0.5 seconds).";
    }

    // Check Volume (RMS)
    const rawData = audioBuffer.getChannelData(0); // Analyze first channel
    let sum = 0;
    // Check a subset of samples for performance
    const sampleStep = Math.floor(rawData.length / 5000) || 1; 
    let samplesChecked = 0;

    for (let i = 0; i < rawData.length; i += sampleStep) {
      const sample = rawData[i];
      sum += sample * sample;
      samplesChecked++;
    }

    const rms = Math.sqrt(sum / samplesChecked);
    audioContext.close();

    // Threshold: 0.005 is very quiet (~-46dB)
    if (rms < 0.005) {
      return "Audio volume is extremely low. It may be too quiet to transcribe accurately.";
    }

    return null;
  } catch (e) {
    console.warn("Audio analysis failed, proceeding anyway:", e);
    return null; 
  }
};

