  // Quality Check States
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [qualityWarning, setQualityWarning] = useState<string | null>(null);
  const [pendingBlob, setPendingBlob] = useState<Blob | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const timerRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // To stop recording if component unmounts
  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  const startRecording = async () => {
    // Clear previous warnings
    setQualityWarning(null);
    setPendingBlob(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        // Stop all tracks to release microphone
        stream.getTracks().forEach(track => track.stop());

        // Pass blob to processing flow
        processAudio(blob);
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);

      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      onTranscriptionError("Could not access microphone. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQualityWarning(null);
    setPendingBlob(null);

    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 500 * 1024 * 1024) { // 500MB limit
        onTranscriptionError("File size too large. Please upload files under 500MB.");
        return;
      }
      processAudio(file);
    }
  };

  const processAudio = async (blob: Blob) => {
    setIsAnalyzing(true);
    const warning = await analyzeAudioQuality(blob);
    setIsAnalyzing(false);

    if (warning) {
      setQualityWarning(warning);
      setPendingBlob(blob);
    } else {
      executeTranscription(blob);
    }
  };

  const executeTranscription = async (blob: Blob) => {
    onTranscriptionStart();
    try {
      const { transcribeAudio } = await import('../services/geminiService');
      const result = await transcribeAudio(blob, selectedLanguage, template, isJsonMode);
      onTranscriptionComplete(result.text, result.json);
    } catch (error: any) {
      onTranscriptionError(error.message);
    }
  };

  const handleProceedAnyway = () => {
    if (pendingBlob) {
      setQualityWarning(null);
      executeTranscription(pendingBlob);
      setPendingBlob(null);
    }
  };

  const handleRetry = () => {
    setQualityWarning(null);
    setPendingBlob(null);
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const isProcessing = currentState === 'processing' || isAnalyzing;

  return (
    <div className="flex flex-col items-center justify-center space-y-8 w-full max-w-md mx-auto p-6 relative">

      {/* Quality Warning Overlay */}
      {qualityWarning && (
        <div className="absolute inset-0 bg-white/95 z-20 flex flex-col items-center justify-center p-6 text-center rounded-3xl animate-fade-in border-2 border-amber-100 shadow-lg">
          <div className="w-12 h-12 bg-amber-100 text-amber-500 rounded-full flex items-center justify-center mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h3 className="text-lg font-bold text-slate-800 mb-2">Poor Audio Quality</h3>
          <p className="text-slate-600 mb-6 text-sm leading-relaxed">{qualityWarning}</p>
          <div className="flex flex-col w-full gap-3 sm:flex-row">
            <button 
              onClick={handleRetry} 
              className="flex-1 px-4 py-2 border border-slate-200 text-slate-700 font-medium rounded-xl hover:bg-slate-50 transition-colors"
            >
              {mode === 'record' ? 'Re-record' : 'Upload New'}
            </button>
            <button 
              onClick={handleProceedAnyway} 
              className="flex-1 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white font-medium rounded-xl transition-colors shadow-sm"
            >
              Transcribe Anyway
            </button>
          </div>
        </div>
      )}

      {/* Mode Toggle & Language - Only show when idle */}
      {!isRecording && !isProcessing && (
        <div className="w-full space-y-6 animate-fade-in">

          {/* Mode Switcher */}
          <div className="flex p-1 bg-slate-100 rounded-xl">
            <button
              onClick={() => setMode('record')}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${
                mode === 'record' 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Record Audio
            </button>
            <button
              onClick={() => setMode('upload')}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${
                mode === 'upload' 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Upload File
            </button>
          </div>

          {/* Language Selector */}
          <div>
            <label htmlFor="language-select" className="block text-xs font-semibold text-slate-500 mb-2 uppercase tracking-wider text-center">
              Target Language / Dialect
            </label>
            <div className="relative">
              <select
                id="language-select"
                value={selectedLanguage}
                onChange={(e) => setSelectedLanguage(e.target.value)}
                className="block w-full pl-4 pr-10 py-2.5 text-base border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-xl bg-slate-50 text-slate-700 shadow-sm transition-all hover:bg-white cursor-pointer"
              >
                {LANGUAGES.map((lang) => (
                  <option key={lang} value={lang}>
