import React, { useRef } from 'react';

export interface TemplateSelectorProps {
  template: string;
  onTemplateChange: (template: string) => void;
  mode: 'general' | 'meeting' | 'custom' | 'word_template';
  onModeChange: (mode: 'general' | 'meeting' | 'custom' | 'word_template') => void;
  wordTemplateName: string | null;
  onWordTemplateUpload: (file: File) => void;
}

export const MEETING_TEMPLATE = `# Meeting Minutes

**Title of Meeting:** [Extract Title]
**Date of Meeting:** [Extract Date]
**Members Present:** [List Members]

## Objective of Meeting
[Summarize the main objective]

## Points of Discussion
- [Point 1]
- [Point 2]
- [Point 3]

## Decisions Made
- [Decision 1]
- [Decision 2]

## Next Steps
- [Action Item 1] (Assignee: [Name])
- [Action Item 2] (Assignee: [Name])
`;

// Instructions for the JSON extraction when using a Word template
export const WORD_TEMPLATE_INSTRUCTIONS = `Extract the following information from the audio to fill a Word document template:

- title: The title of the meeting or note.
- date: The date of the recording.
- transcription: The full, verbatim text of the voice memo.
- summary: A concise summary of the content.
- key_points: A list of key points (as text with bullets).
- action_items: A list of action items or next steps.

Return the result as a valid JSON object with these exact keys.
`;

export const TemplateSelector: React.FC<TemplateSelectorProps> = ({
  template,
  onTemplateChange,
  mode,
  onModeChange,
  wordTemplateName,
  onWordTemplateUpload
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const wordInputRef = useRef<HTMLInputElement>(null);

  const handleModeChange = (newMode: 'general' | 'meeting' | 'custom' | 'word_template') => {
    onModeChange(newMode);
    if (newMode === 'meeting') {
      onTemplateChange(MEETING_TEMPLATE);
    } else if (newMode === 'general') {
      onTemplateChange('');
    } else if (newMode === 'word_template') {
       // Set default instructions only if user hasn't set custom ones or it was the default
       if (!template || template === MEETING_TEMPLATE) {
         onTemplateChange(WORD_TEMPLATE_INSTRUCTIONS);
       }
    }

    if (newMode === 'custom' && mode === 'general') {
        onTemplateChange(MEETING_TEMPLATE); 
    }
  };

  const handleTextFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        onTemplateChange(text);
        onModeChange('custom');
      };
      reader.readAsText(file);
    }
  };

  const handleWordFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onWordTemplateUpload(file);
    }
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 mb-6 shadow-sm animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-4">
        <div>
           <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Output Format</h3>
           <p className="text-xs text-slate-500">Choose how to structure the notes</p>
        </div>

        <div className="flex flex-wrap gap-1 bg-slate-100 rounded-lg p-1">
          <button
            onClick={() => handleModeChange('general')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'general' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            General
          </button>
          <button
            onClick={() => handleModeChange('meeting')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'meeting' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Meeting Minutes
          </button>
          <button
            onClick={() => handleModeChange('custom')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'custom' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Custom Text
          </button>
          <button
            onClick={() => handleModeChange('word_template')}
            className={`px-3 py-1.5 text-xs sm:text-sm font-medium rounded-md transition-all ${
              mode === 'word_template' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Word Template
          </button>
        </div>
      </div>

      {mode === 'word_template' && (
        <div className="space-y-4 animate-fade-in bg-indigo-50/50 p-4 rounded-lg border border-indigo-100">
           <div className="flex items-center justify-between">
              <div>
                 <h4 className="text-sm font-semibold text-indigo-900">1. Upload Word Document Design</h4>
                 <p className="text-xs text-indigo-600 mt-1">
                    Upload a .docx file containing placeholders like <code>{`{client_name}`}</code>, <code>{`{summary}`}</code>, or <code>{`{transcription}`}</code>.
                 </p>
              </div>
              <button 
                  onClick={() => wordInputRef.current?.click()}
                  className="px-4 py-2 bg-white border border-indigo-200 text-indigo-700 rounded-lg text-sm font-medium hover:bg-indigo-50 shadow-sm flex items-center gap-2"
              >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  {wordTemplateName ? 'Change Template' : 'Upload .docx'}
              </button>
              <input 
                  type="file" 
                  ref={wordInputRef} 
                  className="hidden" 
                  accept=".docx" 
                  onChange={handleWordFileUpload}
               />
           </div>

           {wordTemplateName && (
             <div className="flex items-center gap-2 text-sm text-green-700 bg-green-50 px-3 py-2 rounded-md border border-green-200">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                </svg>
                Template loaded: <strong>{wordTemplateName}</strong>
             </div>
           )}

           <div className="pt-2 border-t border-indigo-100">
              <h4 className="text-sm font-semibold text-indigo-900 mb-2">2. Extraction Instructions (Auto-detected)</h4>
              <p className="text-xs text-indigo-600 mb-2">
                We scanned your document and found these placeholders. Modify the instructions below if needed.
              </p>
              <textarea
                value={template}
                onChange={(e) => onTemplateChange(e.target.value)}
                placeholder="Extract the following keys: {title}, {date}..."
                className="w-full h-32 p-3 text-sm font-mono text-slate-700 bg-white border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-y"
              />
           </div>
        </div>
      )}

      {(mode === 'meeting' || mode === 'custom') && (
        <div className="space-y-3 animate-fade-in">
          <div className="relative">
            <textarea
              value={template}
              onChange={(e) => {
                  onTemplateChange(e.target.value);
                  if (mode !== 'custom') onModeChange('custom');
              }}
              placeholder="Enter your template structure here..."
              className="w-full h-48 p-3 text-sm font-mono text-slate-700 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-y"
            />
            {mode === 'custom' && (
                <div className="absolute top-2 right-2">
                     <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="text-xs bg-white border border-slate-300 text-slate-600 px-2 py-1 rounded hover:bg-slate-50 flex items-center gap-1 shadow-sm"
                     >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                        </svg>
                        Upload Text
                     </button>
                     <input 
                        type="file" 
                        ref={fileInputRef} 
                        className="hidden" 
                        accept=".txt,.md" 
                        onChange={handleTextFileUpload}
                     />
                </div>
            )}
          </div>
          <p className="text-xs text-slate-500 italic">
            Gemini will extract info from the audio to fill the placeholders in your template.
          </p>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { AudioRecorder } from './components/AudioRecorder';
import { TemplateSelector, WORD_TEMPLATE_INSTRUCTIONS } from './components/TemplateSelector';
import { TranscriptionState } from './types';

// Declare globals for libraries loaded via script tags
declare const marked: any;
declare const PizZip: any;
declare const docxtemplater: any;
declare const saveAs: any;

const App: React.FC = () => {
  const [state, setState] = useState<TranscriptionState>({
    status: 'idle',
    text: null,
    error: null,
    jsonResult: null
  });
  const [template, setTemplate] = useState<string>('');
  const [templateMode, setTemplateMode] = useState<'general' | 'meeting' | 'custom' | 'word_template'>('general');
  const [wordTemplateFile, setWordTemplateFile] = useState<ArrayBuffer | null>(null);
  const [wordTemplateName, setWordTemplateName] = useState<string | null>(null);

  const handleStart = () => {
    setState({ ...state, status: 'processing', error: null });
  };

  const handleComplete = (text: string, json?: any) => {
    setState({ status: 'success', text, jsonResult: json, error: null });
  };

  const handleError = (error: string) => {
    setState({ status: 'error', text: null, error, jsonResult: null });
  };

  const reset = () => {
    setState({ status: 'idle', text: null, error: null, jsonResult: null });
  };

  const handleWordTemplateUpload = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        const arrayBuffer = e.target.result as ArrayBuffer;
        setWordTemplateFile(arrayBuffer);
        setWordTemplateName(file.name);

        // Auto-detect placeholders to help the user
        try {
          const zip = new PizZip(arrayBuffer);
          // Try to read the document content
          let xml = "";
          if (zip.files['word/document.xml']) {
             xml = zip.files['word/document.xml'].asText();
          }

          // Naive text extraction to find {placeholders}
          // Remove XML tags to treat it as text
          const textBody = xml.replace(/<[^>]+>/g, '');

          // Regex to find {variable} pattern
          const matches = textBody.match(/\{[a-zA-Z0-9_]+\}/g);

          if (matches && matches.length > 0) {
            // Extract variable names without braces
            const vars = matches.map((m: string) => m.replace(/[\{\}]/g, ''));
            const uniqueVars = [...new Set(vars)];

            const newInstruction = `The uploaded Word template contains the following placeholders:
${uniqueVars.map(v => `- ${v}`).join('\n')}

Instructions:
1. Analyze the audio and extract data for the keys above.
2. Return a valid JSON object matching these keys exactly.
3. If a key seems to request the full text (e.g. 'transcript', 'transcription', 'full_text', 'memo'), provide the complete text of the recording.
4. For other keys, extract the specific details requested.
5. If information is missing, use "N/A".`;

            setTemplate(newInstruction);
          } else {
             // Fallback if we couldn't detect simple placeholders
             setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
          }
        } catch (err) {
           console.warn("Failed to analyze template placeholders", err);
           setTemplate(WORD_TEMPLATE_INSTRUCTIONS);
        }
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handlePrintPDF = () => {
    window.print();
  };

  const handleExportWord = () => {
    // If we have a JSON result and a Word template, use docxtemplater
    if (state.jsonResult && wordTemplateFile && templateMode === 'word_template') {
       try {
         const zip = new PizZip(wordTemplateFile);
         const doc = new docxtemplater(zip, {
            paragraphLoop: true,
            linebreaks: true,
         });

         // Render the document with the JSON data from Gemini
         doc.render(state.jsonResult);

         const out = doc.getZip().generate({
            type: "blob",
            mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
         });

         saveAs(out, `filled_${wordTemplateName || 'document.docx'}`);
       } catch (error: any) {
          console.error("Docxtemplater error:", error);

          let msg = "Error generating Word document.";
          if (error.properties && error.properties.errors) {
              const errs = error.properties.errors.map((e: any) => e.message).join(', ');
              msg += ` Details: ${errs}`;
          }
          alert(msg);
       }
       return;
    }

    // Fallback: Export standard Markdown/HTML to Word
    if (!state.text) return;

    let htmlContent = '';
    if (typeof marked !== 'undefined') {
       htmlContent = marked.parse(state.text);
    } else {
       htmlContent = `<pre>${state.text}</pre>`;
    }

    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' " +
         "xmlns:w='urn:schemas-microsoft-com:office:word' " +
         "xmlns='http://www.w3.org/TR/REC-html40'>" +
         "<head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title>" +
         "<style>body { font-family: 'Calibri', sans-serif; font-size: 11pt; }</style>" +
         "</head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + htmlContent + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = 'meeting_notes.doc';
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const getMarkdownHtml = (text: string | null) => {
    if (!text) return { __html: '' };
    if (typeof marked !== 'undefined') {
      return { __html: marked.parse(text) };
    }
    return { __html: text };
  };

