                    </svg>
                  </button>
                  <button 
                    onClick={reset}
                    className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                    title="New recording"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                  </button>
                </div>
              </div>

              <div id="results-container" className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 md:p-10">
                <h1 className="text-3xl font-bold mb-6 hidden print-only">Transcribed Notes</h1>

                {/* Render JSON as text if in JSON mode, otherwise Render Markdown */}
                {state.jsonResult ? (
                  <div className="space-y-4">
                    <div className="bg-green-50 border border-green-200 rounded-lg p-4 flex items-start gap-3">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-green-600 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                       </svg>
                       <div>
                         <h3 className="text-green-800 font-semibold text-sm">Data Ready for Insertion</h3>
                         <p className="text-green-700 text-sm mt-1">
                           Gemini has successfully extracted the data below. Click the <strong>Download Filled Word Doc</strong> button to generate your final document.
                         </p>
                       </div>
                    </div>

                    <div className="bg-slate-50 p-4 rounded-lg font-mono text-sm overflow-x-auto border border-slate-200">
                      <pre className="text-indigo-700">{JSON.stringify(state.jsonResult, null, 2)}</pre>
                    </div>
                  </div>
                ) : (
                  <div 
                    className="prose prose-slate max-w-none prose-headings:font-semibold prose-a:text-indigo-600"
                    dangerouslySetInnerHTML={getMarkdownHtml(state.text)}
                  />
                )}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Simple Footer */}
      <footer className="py-8 text-center text-slate-400 text-sm no-print">
        <p>&copy; {new Date().getFullYear()} Gemini Audio Transcriber</p>
      </footer>
    </div>
  );
};

export default App;
